const express = require('express');

const app = express();

// Drfine a router for the URL
const PORT = 3000;

// Root URL into server

    app.get('/', (req, res) => {
        res.send("Express server is running...!");
    });

    // starting running the server
    app.listen(PORT, ()=> {
        console.log("Server is running on port" + PORT);
    });

    